                                    type="tel"
                                    pattern="[0-9]*"
                                    className="w-full p-4 pl-8 bg-gray-50 border border-gray-100 rounded-xl focus:ring-2 focus:ring-brand-clay focus:border-transparent outline-none transition-all" 
                                    placeholder="52 322 140 6649" 
                                  />
