import { toISODate, addDays } from './dateUtils';

// Parse a single date string from ICS format (YYYYMMDD)
// Handles both YYYYMMDD and YYYYMMDDTHHMMSSZ formats
const parseIcalDate = (dateStr: string): Date | null => {
  if (!dateStr) return null;
  // Clean up the string - keep only digits for the initial YYYYMMDD check
  const cleanStr = dateStr.replace(/[^0-9T]/g, '');
  if (cleanStr.length < 8) return null;

  const year = parseInt(cleanStr.substring(0, 4), 10);
  const month = parseInt(cleanStr.substring(4, 6), 10) - 1; // JS months are 0-indexed
  const day = parseInt(cleanStr.substring(6, 8), 10);

  // Return a Date object at local midnight to ensure consistent comparison
  return new Date(year, month, day, 0, 0, 0);
};

const fetchWithProxy = async (url: string, proxyUrlBuilder: (url: string) => string): Promise<string> => {
  const proxyUrl = proxyUrlBuilder(url);
  const response = await fetch(proxyUrl);
  if (!response.ok) {
    throw new Error(`Status ${response.status}`);
  }
  return await response.text();
};

export const fetchAndParseIcal = async (url: string): Promise<string[]> => {
  let data = '';

  // Cache Buster: Appends a unique timestamp to the Airbnb URL
  // This forces proxies like corsproxy.io to fetch a fresh version instead of a stale cached one.
  const buster = `cacheBust=${Date.now()}`;
  const urlWithBuster = url.includes('?') ? `${url}&${buster}` : `${url}?${buster}`;

  try {
    // Strategy 1: corsproxy.io (Primary)
    data = await fetchWithProxy(urlWithBuster, (u) => `https://corsproxy.io/?${encodeURIComponent(u)}`);
  } catch (err1) {
    try {
      // Strategy 2: allorigins.win (Backup)
      data = await fetchWithProxy(urlWithBuster, (u) => `https://api.allorigins.win/raw?url=${encodeURIComponent(u)}`);
    } catch (err2) {
      console.error('All calendar fetch proxies failed:', err2);
      return [];
    }
  }

  try {
    const blockedDates: Set<string> = new Set();

    // Normalize line endings
    const lines = data.split(/\r\n|\n|\r/);
    let inEvent = false;
    let startStr: string | null = null;
    let endStr: string | null = null;

    for (const line of lines) {
      const trimmedLine = line.trim();

      if (trimmedLine.startsWith('BEGIN:VEVENT')) {
        inEvent = true;
        startStr = null;
        endStr = null;
      } else if (trimmedLine.startsWith('END:VEVENT')) {
        inEvent = false;

        if (startStr && endStr) {
          const startDate = parseIcalDate(startStr);
          const endDate = parseIcalDate(endStr);

          if (startDate && endDate) {
            let current = new Date(startDate);
            // Iterate from start date up to (but not including) end date
            // This is the standard iCal behavior: end date is the checkout day
            while (current < endDate) {
              blockedDates.add(toISODate(current));
              current = addDays(current, 1);
            }
          }
        }
      } else if (inEvent) {
        // Robust Regex Parsing:
        // Handles variations like DTSTART:20250101 and DTSTART;VALUE=DATE:20250101
        // which Airbnb uses interchangeably for Reserved vs Blocked dates.
        const startMatch = trimmedLine.match(/^DTSTART.*:(.*)$/);
        if (startMatch) startStr = startMatch[1].trim();

        const endMatch = trimmedLine.match(/^DTEND.*:(.*)$/);
        if (endMatch) endStr = endMatch[1].trim();
      }
    }

    return Array.from(blockedDates);
  } catch (error) {
    console.error('Error parsing calendar data:', error);
    return [];
  }
};

import { Property } from '../types';

// Constants
const HIGH_SEASON_START_MONTH = 9; // October (0-indexed)
const HIGH_SEASON_START_DAY = 27;
const HIGH_SEASON_END_MONTH = 3; // April (0-indexed)
const HIGH_SEASON_END_DAY = 30;

// Mexican Holidays (Fixed dates for simplicity, can be expanded)
// Format: MM-DD
const HOLIDAYS = [
  '01-01', // New Year's
  '02-05', // Constitution Day
  '03-21', // Benito Juarez
  '05-01', // Labor Day
  '09-16', // Independence Day
  '11-20', // Revolution Day
  '12-25', // Christmas
];

// Room Tiers
const TIER_1_IDS = ['1', '2', '3'];
const TIER_2_IDS = ['4', '9'];
const TIER_3_IDS = ['5', '6', '7', '8', '10'];

const getBasePrice = (propertyId: string, date: Date): number => {
  const month = date.getMonth();
  const day = date.getDate();

  // Determine Season
  // High Season: Oct 27 - Apr 30
  // Low Season: May 1 - Oct 26

  let isHighSeason = false;

  // Check if we are in the months firmly within High Season (Nov, Dec, Jan, Feb, Mar)
  if (month > 9 || month < 3) {
    isHighSeason = true;
  }
  // Check boundary month: October
  else if (month === 9 && day >= 27) {
    isHighSeason = true;
  }
  // Check boundary month: April
  else if (month === 3 && day <= 30) {
    isHighSeason = true;
  }

  if (isHighSeason) {
    if (TIER_1_IDS.includes(propertyId)) return 56;
    if (TIER_2_IDS.includes(propertyId)) return 48; // Rooms 4 & 9 (Assuming 5 was a typo in user prompt as it's in Tier 3)
    return 52; // Rooms 5–8 & 10 (Tier 3)
  } else {
    // Low Season
    if (TIER_1_IDS.includes(propertyId)) return 34;
    if (TIER_2_IDS.includes(propertyId)) return 30; // Rooms 4 & 9
    return 32; // Rooms 5–8 & 10
  }
};

export const getNightlyPrice = (propertyId: string, date: Date): number => {
  let price = getBasePrice(propertyId, date);
  const now = new Date();

  // 1. Weekend Modifier (+10%)
  // Friday (5) and Saturday (6)
  const dayOfWeek = date.getDay();
  if (dayOfWeek === 5 || dayOfWeek === 6) {
    price = price * 1.10;
  }

  // 2. Holiday Modifier (+10%)
  const dateString = `${String(date.getMonth() + 1).padStart(2, '0')}-${String(date.getDate()).padStart(2, '0')}`;
  if (HOLIDAYS.includes(dateString)) {
    price = price * 1.10;
  }

  // 3. Last Minute Discount (-10%)
  // Within 7 days of arrival (now)
  const diffTime = date.getTime() - now.getTime();
  const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24));

  if (diffDays >= 0 && diffDays <= 7) {
    price = price * 0.90;
  }

  // Round to nearest whole number for clean display
  return Math.ceil(price);
};

export const calculateTripPricing = (propertyId: string, startDate: Date, endDate: Date) => {
  let subtotal = 0;
  let currentDate = new Date(startDate);
  // Normalize dates to midnight to ensure loop works correctly
  currentDate.setHours(0,0,0,0);
  const end = new Date(endDate);
  end.setHours(0,0,0,0);

  let nights = 0;

  // Loop through each night
  while (currentDate < end) {
    subtotal += getNightlyPrice(propertyId, currentDate);

    // Add 1 day
    currentDate.setDate(currentDate.getDate() + 1);
    nights++;
  }

  // Length of Stay Discounts
  // 7–27 nights: –10% (Updated from 20%)
  // 28+ nights: –40%
  let discountMultiplier = 1;
  let discountLabel = '';

  if (nights >= 28) {
    discountMultiplier = 0.60;
    discountLabel = 'Monthly Discount (40%)';
  } else if (nights >= 7) {
    discountMultiplier = 0.90;
    discountLabel = 'Weekly Discount (10%)';
  }

  const finalTotal = subtotal * discountMultiplier;
  const discountAmount = subtotal - finalTotal;

  return {
    subtotal,
    discountAmount,
    discountLabel,
    total: finalTotal,
    nights
  };
};

